export default {
  async fetch(request, env) {
    try {
      const url = new URL(request.url);
      const path = url.pathname;
      
      // Authentication check
      const authHeader = request.headers.get('Authorization');
      if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return new Response(JSON.stringify({ error: 'Unauthorized' }), {
          status: 401,
          headers: { 'Content-Type': 'application/json' }
        });
      }
      
      const token = authHeader.substring(7);
      if (token !== env.API_TOKEN) {
        return new Response(JSON.stringify({ error: 'Invalid token' }), {
          status: 401,
          headers: { 'Content-Type': 'application/json' }
        });
      }
      
      if (path.startsWith('/email')) {
        return await handleEmail(request, env);
      } else if (path.startsWith('/payment')) {
        return await handlePayment(request, env);
      } else {
        return new Response(JSON.stringify({ error: 'Endpoint not found' }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      console.error('Worker error:', error);
      return new Response(JSON.stringify({ error: 'Internal server error' }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

async function handleEmail(request, env) {
  try {
    const body = await request.json();
    
    // Validate email data
    if (!body.to || !body.subject || !body.html) {
      return new Response(JSON.stringify({ error: 'Missing required email fields' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }
    
    const sendGridResponse = await fetch('https://api.sendgrid.com/api/mail.send.json', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${env.SENDGRID_API_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        to: body.to,
        from: env.FROM_EMAIL,
        subject: body.subject,
        html: body.html
      })
    });
    
    if (!sendGridResponse.ok) {
      const errorData = await sendGridResponse.json();
      return new Response(JSON.stringify({ error: 'Email sending failed', details: errorData }), {
        status: sendGridResponse.status,
        headers: { 'Content-Type': 'application/json' }
      });
    }
    
    return new Response(JSON.stringify({ success: true }), {
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (error) {
    console.error('Email error:', error);
    return new Response(JSON.stringify({ error: 'Failed to send email' }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

async function handlePayment(request, env) {
  try {
    const body = await request.json();
    
    // Validate payment data
    if (!body.amount || !body.currency || !body.payment_method_id) {
      return new Response(JSON.stringify({ error: 'Missing required payment fields' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }
    
    const stripeResponse = await fetch('https://api.stripe.com/v1/charges', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: new URLSearchParams({
        amount: Math.round(body.amount * 100),
        currency: body.currency,
        payment_method: body.payment_method_id,
        capture: 'true'
      })
    });
    
    if (!stripeResponse.ok) {
      const errorData = await stripeResponse.json();
      return new Response(JSON.stringify({ error: 'Payment processing failed', details: errorData }), {
        status: stripeResponse.status,
        headers: { 'Content-Type': 'application/json' }
      });
    }
    
    const paymentData = await stripeResponse.json();
    return new Response(JSON.stringify({ 
      success: true, 
      charge_id: paymentData.id,
      amount: paymentData.amount,
      currency: paymentData.currency 
    }), {
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (error) {
    console.error('Payment error:', error);
    return new Response(JSON.stringify({ error: 'Payment processing failed' }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}